import json, os, torch
ck='checkpoints/baseline/model.pt'
print('CKPT', json.dumps(torch.load(ck,map_location='cpu').get('params',{}), sort_keys=True))
for path in ['logs/iter_17/sweep_params.json','logs/iter_23/agent1_control.json','local_eval/out.json','local_eval/out_latched.json','local_eval/out_planner.json']:
    if not os.path.exists(path):
        print('MISSING', path); continue
    try:
        data=json.load(open(path))
    except Exception as e:
        print('BAD', path, e); continue
    print('\nFILE', path)
    if isinstance(data, list):
        # group by name/mode if possible
        groups={}
        for r in data:
            key=r.get('name', r.get('mode','row')) if isinstance(r,dict) else 'row'
            groups.setdefault(key,[]).append(r)
        for k, rows in groups.items():
            vals=lambda field:[float(r.get(field,0)) for r in rows if isinstance(r,dict) and field in r]
            succ=vals('succ') or vals('nav_seek_success')
            safe=vals('safe') or vals('safe_follow_steps')
            latch=vals('latch_step') or vals('first_latch_step')
            print(k, 'n',len(rows),'succ',sum(succ)/len(succ) if succ else None,'safe',sum(safe)/len(safe) if safe else None,'latch',sum(latch)/len(latch) if latch else None)
    elif isinstance(data, dict):
        keys=['nav_seek_success','safe_follow_steps','nav_to_pos_success','found_human_rate_over_epi','avg_robot_to_human_dis_over_epi','total_episodes']
        print({k:data.get(k) for k in keys if k in data})
        pe=data.get('per_episode') or []
        if pe:
            rows=sorted([(r.get('safe_follow_steps',0), r.get('first_latch_step',None), r.get('nav_seek_success',0), r.get('episode_id')) for r in pe])
            print('low5', rows[:5])
            print('high5', rows[-5:])
